INSERT INTO acq_companies (name, hq, sector, revenue_b, employees_k, corridor_countries, eigen_briques, eigen_score, tier, pipeline_stage, priority, website, notes, trojan_horse, annual_value_estimate) VALUES
('Orange','FR','TEL',0.0025,10,'{FR,MA,SN,CI}','NAMYBR',9,'Tier 3','identified','P0','orange.com','Premier opérateur télécom EU avec présence dans 18 pays africains via Orange MEA. Orange Money dépasse 30M de wallets actifs, faisant d''Orange une infrastructure financière autant que télécom sur le corridor.','AMANA × Orange Money Zakat — don digital traçable et certifié halal sur Orange Money pendant le Ramadan, pilote au Maroc/Sénégal/Côte d''Ivoire',1000),
('BNP Paribas','FR','BNK',0.0018,10,'{FR,MA,SN,CI}','NAMZBR',9,'Tier 3','identified','P0','group.bnpparibas.com','Première banque européenne par actifs, présente en Afrique via des filiales au Maroc, Sénégal, Tunisie et Côte d''Ivoire. Contrairement à SocGen, BNP a choisi la stabilité sur le continent et renforce son offre grande clientèle corporate.','NOOS × Jeune Banquier du Corridor — programme de due diligence gratuit pour les 50 meilleurs dossiers de financement PME corridor soumis par les filiales africaines BNP',1000),
('TotalEnergies','FR','ENR',0.0032,10,'{FR,MA,SN,CI}','NBYR',6,'Tier 3','identified','P2','totalenergies.com','Major pétrolier et gazier opérant dans +30 pays africains, avec des projets structurants au Mozambique, Nigeria, Angola, Congo et Sénégal. TotalEnergies est aussi le premier producteur d''énergie solaire décentralisée en Afrique subsaharienne via ses filiales.','YrKnown × Les Gardiens du Mozambique LNG — capturer en vidéo le savoir des ingénieurs seniors TotalEnergies sur la reprise du chantier $20Mds post-force-majeure, patrimoine industriel rare',1000),
('Attijariwafa Bank','MA','BNK',0.0022,10,'{MA,SN,CI,FR}','NAMZBR',9,'Tier 3','identified','P0','attijariwafabank.com','Première banque du Maghreb et 7e d''Afrique, présente dans 25 pays africains avec +11M de clients. Principal vecteur de l''intégration financière africaine portée par le Maroc.','MIZAN × Indice Équité Attijariwafa — scoring ESG et inclusion financière gratuit pour les 500 PME africaines financées par Attijariwafa, co-brandé avec El Kettani pour le Sommet UA 2027',1000),
('Bank of Africa (BMCE)','MA','BNK',0.0015,10,'{MA,SN,CI,FR}','NAMZBR',9,'Tier 3','identified','P0','bankofafrica.net','Groupe bancaire panafricain filiale de FinanceCom (Othman Benjelloun), présent dans 20+ pays africains. Acteur de référence du financement des PME et du commerce intra-africain.','ÆLYA × Medersat.com Digital — extension du programme d''écoles rurales de Benjelloun vers une plateforme de consentement et d''identité numérique pour les élèves des zones non couvertes',1000),
('AXA','FR','INS',0.0028,10,'{FR,MA,SN,CI}','NABZR',8,'Tier 3','identified','P1','axa.com','Premier assureur mondial opérant dans 14 pays africains via AXA Africa & Türkiye, avec une stratégie d''inclusion financière portée par la microassurance SAWA en Egypte et un focus affiché sur la santé mentale au travail.','NOOS × Check-Up Mental Assuré — outil de due diligence bien-être collaborateurs co-développé avec AXA, gratuit pour les 10 000 PME assurées AXA en Afrique, intégré au rapport Mind Health',1000),
('Siemens Energy','DE','IND',0.0019,10,'{DE,FR}','NABR',6,'Tier 3','identified','P2','siemens-energy.com','Leader mondial des équipements et solutions d''énergie, présent dans 29 bureaux MEA avec +4000 employés dédiés. Acteur central de la transition énergétique en Afrique (éolien, solaire, réseau, hydrogène).','YrKnown × Mémoire des Bâtisseurs du Réseau — capturer le savoir des ingénieurs Siemens ayant construit les infrastructures énergétiques africaines avant les retraites massives 2025-2028',1000),
('Sanofi','FR','PHR',0.0016,10,'{FR,MA,SN,CI}','NAMR',6,'Tier 3','identified','P2','sanofi.com','Géant pharmaceutique français classé 3e mondial à l''Access to Medicine Index 2024, avec des partenariats de transfert technologique vaccins en Afrique (BioVac Afrique du Sud, UNICEF). Présent dans +30 pays africains.','ÆLYA × Consentement Patient Zéro — protocole de consentement éclairé digital pour les essais cliniques et campagnes de vaccination en Afrique, co-signé Sanofi/UNICEF',1000),
('OCP Group','MA','MIN',0.0035,10,'{MA,SN,CI,FR}','NBZR',6,'Tier 3','identified','P2','ocpgroup.ma','Groupe minier marocain, 1er exportateur mondial de phosphates et engrais, présent dans 40+ pays africains via ses programmes AgriFertilizer et UM6P. Pilier du corridor EU-Afrique pour la sécurité alimentaire.','YrKnown × Les Derniers Maîtres de Khouribga — capturer en vidéo et audio le savoir des ingénieurs mines OCP avant départ à la retraite, patrimoine industriel irremplaçable du Maroc',1000),
('Holmarcom','MA','BNK',0.0012,10,'{MA,SN,CI,FR}','NAMZBR',9,'Tier 3','identified','P0','holmarcom.ma','Conglomérat marocain diversifié (assurance, banque, agroalimentaire, distribution), fondé par la famille Bensalah. Actionnaire de référence de Wafa Assurance et Crédit du Maroc, en phase d''internationalisation après investissement IFC de 135M USD fin 2024.','AMANA × Association Yza — projet d''accès à l''eau potable dans les douars autour de Khouribga co-porté avec l''amie de la mère du fondateur, narratif familial et territorial puissant',1000),
('Société Générale','FR','BNK',0.0009,10,'{FR,MA,SN,CI}','NAMZBR',9,'Tier 3','identified','P0','societegenerale.com','Banque française en retrait stratégique d''Afrique subsaharienne (cessions Congo, Guinée, Mauritanie, Tchad 2023-2024) mais maintenant une présence stratégique forte au Maroc via SG Maroc.','BURHAN × SG Maroc Green Trace — protocole de traçabilité CRMA pour le financement des projets d''infrastructures vertes au Maroc, vitrine de la stratégie post-retrait subsaharien de SocGen',1000),
('Allianz','DE','INS',0.0017,10,'{DE,FR}','NABZR',8,'Tier 3','identified','P1','allianz.com','Assureur mondial opérant dans 14 pays africains via Allianz Africa, avec 732M EUR de primes brutes. Leader de l''assurance des grandes entreprises et projets d''infrastructure sur le continent.','RAQIB × Allianz Risk Radar Africa — tableau de bord en temps réel des risques géopolitiques, climatiques et infrastructurels pour le portefeuille Allianz Africa, co-brandé avec Delphine Traoré',1000),
('Crédit Agricole','FR','BNK',0.0014,10,'{FR,MA,SN,CI}','NAMZBR',9,'Tier 3','identified','P0','credit-agricole.com','Deuxième banque européenne opérant en Afrique via le Crédit du Maroc (filiale), CIB Afrique et des participations régionales. Acteur croissant du financement de l''agri-business et des PME africaines.','MIZAN × Crédit Vert Agricole Afrique — scoring ESG gratuit pour les 200 projets agri-business financés par le Crédit du Maroc + CA CIB en 2025, aligné avec la taxonomie EU',1000),
('HSBC','GB','BNK',0.0011,10,'{GB,FR}','NAMZBR',9,'Tier 3','identified','P0','hsbc.com','Banque britannique opérant principalement en Afrique du Nord et du Sub-Sahara via ses bureaux corporate et investment banking à Casablanca, Le Caire, Lagos et Johannesburg.','NOOS × HSBC Africa Deal Scorecard — outil de due diligence gratuit pour qualifier les 100 meilleurs dossiers M&A corridors soumis à HSBC CIB, intégrant scoring RAQIB géopolitique',1000),
('Ecobank','TG','BNK',0.002,10,'{TG,FR}','NAMZBR',9,'Tier 3','identified','P0','ecobank.com','Banque panafricaine présente dans 35 pays d''Afrique subsaharienne, seul acteur avec une couverture aussi large du corridor. Spécialisée dans le commerce intra-africain et les transferts de fonds.','AMANA × Ecobank Ramadan Impact Wallet — intégration d''un module de don traçable et certifié sur l''app Ecobank Mobile pendant le Ramadan, pilote en Afrique de l''Ouest et Centrale',1000),
('MTN Group','ZA','TEL',0.0028,10,'{ZA,FR}','NAMYBR',9,'Tier 3','identified','P0','mtn.com','Premier opérateur télécom africain présent dans 19 pays avec +280M de clients. MTN Fintech (MoMo) dépasse 60M de wallets actifs, faisant de MTN le plus grand réseau de mobile money d''Afrique.','BURHAN × MTN MoMo Minerals Track — protocole de traçabilité des paiements miniers sur MoMo pour les artisans mineurs du corridor (DRC, Ghana, Guinée), conformité EU CRMA intégrée',1000),
('Vodafone / Vodacom','GB','TEL',0.0022,10,'{GB,FR}','NAMYBR',9,'Tier 3','identified','P0','vodacom.com','Opérateur télécom sud-africain (filiale Vodafone) présent dans 7 pays africains dont Tanzanie, RDC, Mozambique, Lesotho, Éthiopie. M-Pesa (via Safaricom) est le rail de paiement dominant en Afrique de l''Est.','MYNε × Vodacom M-Pesa Minerals Exchange — marketplace B2B des minéraux critiques tracés sur l''infrastructure M-Pesa pour les coopératives minières d''Afrique de l''Est',1000),
('Maroc Telecom','MA','TEL',0.0013,10,'{MA,SN,CI,FR}','NAMYBR',9,'Tier 3','identified','P0','iam.ma','Opérateur télécom marocain filiale d''Etisalat (UAE), présent dans 9 pays africains (Mali, Burkina Faso, Mauritanie, Gabon, Côte d''Ivoire...). Infrastructure télécom et internet du Maghreb et Afrique de l''Ouest francophone.','RAQIB × IAM Corridor Intelligence Alert — flux d''alertes géopolitiques temps réel pour les 9 filiales IAM africaines, co-brandé avec Benchaaboun pour son agenda de redressement stratégique',1000),
('Deloitte','GB','CNS',0.0038,10,'{GB,FR}','NAMR',6,'Tier 3','identified','P2','deloitte.com','Premier cabinet d''audit et conseil mondial avec une présence dans 40+ pays africains via Deloitte Africa (hub Johannesburg). Leader des missions de transformation digitale et de conformité ESG pour les grandes entreprises du corridor.','NOOS × Deloitte Corridor Readiness Index — outil d''évaluation gratuit de la maturité CRMA des 50 plus grands industriels africains, co-publié avec Deloitte Africa et présenté à l''AfDB Annual Meeting',1000),
('PwC','FR','CNS',0.0032,10,'{FR,MA,SN,CI}','NAMR',6,'Tier 3','identified','P2','pwc.com','Deuxième cabinet mondial d''audit et conseil, avec des bureaux dans 35 pays africains via PwC Africa. Leader de l''accompagnement des transactions M&A et de la structuration fiscale pour les investissements corridor.','MIZAN × PwC Africa ESG Benchmark — rapport annuel gratuit sur la performance ESG des 100 plus grandes entreprises africaines cotées, co-signé PwC / Eigen, distribué à Davos et AU Summit',1000),
('EY','FR','CNS',0.0029,10,'{FR,MA,SN,CI}','NAMR',6,'Tier 3','identified','P2','ey.com','Troisième cabinet mondial présent dans 34 pays africains avec un hub à Casablanca et Johannesburg. Spécialisé dans les transactions M&A, la structuration de fonds et l''accompagnement des IPO sur les marchés africains.','BURHAN × EY Africa Minerals Traceability Lab — laboratoire de recherche appliquée sur la traçabilité des minéraux critiques co-animé EY / Eigen, produisant le premier standard africain de conformité CRMA',1000),
